import React, { useState } from "react";
import "./Signup.css";
import bg from "../images/1stbg.jpg.jpeg"; 

function Signup({ toggleLogin }) {
  const [formData, setFormData] = useState({ name:'', phone:'', email:'', password:'' });
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage('Signing up...');
    setMessageType('');

    try {
      const response = await fetch('http://localhost:5002/api/signup', {
        method: 'POST',
        headers: { 'Content-Type':'application/json' },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok) {
        setMessage(data.message || 'Signup successful!');
        setMessageType('success');
        setFormData({ name:'', phone:'', email:'', password:'' });
      } else {
        setMessage(data.message || 'Signup failed.');
        setMessageType('error');
      }

    } catch {
      setMessage('Network error, try again.');
      setMessageType('error');
    }
  };

  return (
    <div className="signup-container" style={{ backgroundImage: `url(${bg})` }}>
      <div className="signup-box">
        <h1>SIGN UP</h1>
        <form onSubmit={handleSubmit}>
          <input type="text" name="name" placeholder="Name" value={formData.name} onChange={handleChange} required />
          <input type="text" name="phone" placeholder="Phone" value={formData.phone} onChange={handleChange} required />
          <input type="email" name="email" placeholder="Email" value={formData.email} onChange={handleChange} required />
          <input type="password" name="password" placeholder="Password" value={formData.password} onChange={handleChange} required />
          <button type="submit">SIGN UP</button>
          {message && <p style={{ color: messageType==='success'?'green':'red', marginTop:'10px' }}>{message}</p>}
        </form>
        <p>Already have an account? <span onClick={toggleLogin}>Log In</span></p>
      </div>
    </div>
  );
}

export default Signup;
